class Solution(object):
    def maxStability(self, n, edges, k):
        """
        :type n: int
        :type edges: List[List[int]]
        :type k: int
        :rtype: int
        """
        class DSU:
            def __init__(self, n):
                self.parent = list(range(n))
                self.rank = [0] * n

            def find(self, x):
                if self.parent[x] != x:
                    self.parent[x] = self.find(self.parent[x])
                return self.parent[x]

            def union(self, x, y):
                px, py = self.find(x), self.find(y)
                if px == py:
                    return False
                if self.rank[px] < self.rank[py]:
                    px, py = py, px
                self.parent[py] = px
                if self.rank[px] == self.rank[py]:
                    self.rank[px] += 1
                return True

        def can_form_spanning_tree(min_strength):
            """Check if we can form spanning tree with min strength >= min_strength"""
            dsu = DSU(n)

            # First add mandatory edges
            mandatory_edges = [(u, v, s, True) for u, v, s, must in edges if must]

            for u, v, s, _ in mandatory_edges:
                if s < min_strength:
                    return False, -1  # Can't use mandatory edge below threshold
                if not dsu.union(u, v):
                    return False, -1  # Cycle detected

            # Count components
            components = len(set(dsu.find(i) for i in range(n)))
            edges_added = len(mandatory_edges)
            upgrades_used = 0

            # Add optional edges sorted by strength descending
            optional = [(u, v, s) for u, v, s, must in edges if not must]
            optional.sort(key=lambda x: -x[2])

            for u, v, s in optional:
                if components == 1:
                    break

                current_strength = s
                # Try with upgrade if available
                if upgrades_used < k and 2 * s >= min_strength:
                    current_strength = 2 * s
                    upgrades_used += 1
                elif s < min_strength:
                    continue

                if dsu.union(u, v):
                    components -= 1
                    edges_added += 1

            if components == 1 and edges_added == n - 1:
                return True, upgrades_used
            return False, -1

        # Binary search on minimum strength
        left, right = 1, 2 * max(s for _, _, s, _ in edges)
        result = -1

        while left <= right:
            mid = (left + right) // 2
            can_form, _ = can_form_spanning_tree(mid)

            if can_form:
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result
